import React, { useEffect, useRef } from 'react';
import * as d3 from 'd3';
import axios from 'axios';

function UASTLChart({ range }) {
    const d3Container = useRef(null);

    useEffect(() => {
        if (!d3Container.current) return;

        const width = d3Container.current.clientWidth;
        const height = d3Container.current.clientHeight;
        const margin = { top: 40, right: 30, bottom: 60, left: 80 };
        const chartW = width - margin.left - margin.right;
        const chartH = height - margin.top - margin.bottom;

        // 清除之前的內容
        d3.select(d3Container.current).selectAll('*').remove();

        axios.get('http://localhost:3001/api/uastl').then(res => {
            let data = res.data;
            if (!data || data.length === 0) return;

            // 應用range過濾
            if (range && range.length === 2) {
                data = data.slice(range[0], range[1] + 1);
            }

            const n = data.length;
            console.log('Data sample:', data[0]); // 調試用

            // 獲取組件參數
            const seasonalKeys = Object.keys(data[0]).filter(k => k.startsWith('seasonal') && k.endsWith('_mean'));
            const numComponents = 3 + seasonalKeys.length; // input, trend, seasonal, residual
            const numSamples = data[0].num_samples_added || 3;
            const p_used = data[0].p_used ? data[0].p_used.split(',').map(Number) : [7, 90, 365];
            const coPoint = data[0].coPoint_used ? +data[0].coPoint_used - 1 : null;

            console.log('Components:', { seasonalKeys, numComponents, numSamples, p_used, coPoint });

            // 簡單的樣本顏色
            const sampleColors = ['#e74c3c', '#3498db', '#2ecc71', '#f39c12', '#9b59b6'];

            // 置信區間設定
            const sigmaLevels = {
                '50%': 0.674490,
                '99%': 2.575829
            };

            // 組件標題和鍵
            const componentInfo = [
                { title: 'Input Data', key: 'input' },
                { title: 'Trend Component', key: 'trend' },
                ...seasonalKeys.map((k, i) => ({
                    title: `Seasonal Component ${i + 1} (p=${p_used[i] || 'N/A'})`,
                    key: k.replace('_mean', '').replace('seasonal', 'seasonal')
                })),
                { title: 'Residual Component', key: 'residual' }
            ];

            // 創建SVG
            const svg = d3.select(d3Container.current)
                .append('svg')
                .attr('width', width)
                .attr('height', height)
                .style('background', '#fafafa');

            // 主標題
            svg.append('text')
                .attr('x', width / 2)
                .attr('y', 25)
                .attr('text-anchor', 'middle')
                .attr('font-size', 16)
                .attr('font-weight', 'bold')
                .attr('fill', '#333')
                .text('UASTL Decomposition Results (Python Replica)');

            const subplotH = chartH / numComponents;

            // 繪製每個組件
            componentInfo.forEach((comp, i) => {
                const g = svg.append('g')
                    .attr('transform', `translate(${margin.left}, ${margin.top + i * subplotH})`);

                // 獲取數據
                const meanKey = `${comp.key}_mean`;
                const stdKey = `${comp.key}_std`;
                const corrKey = `corr_${comp.key}`;

                const mean = data.map(d => +d[meanKey]).filter(v => !isNaN(v));
                const std = data.map(d => +d[stdKey]).filter(v => !isNaN(v));
                const corr = data.map(d => +d[corrKey] || 0); // 默認為0而不是過濾

                console.log(`Component ${i} (${comp.key}):`, {
                    meanKey, stdKey, corrKey,
                    meanLen: mean.length,
                    stdLen: std.length,
                    corrLen: corr.length,
                    corrSample: corr.slice(0, 5)
                });

                if (mean.length === 0 || std.length === 0) return;

                const dataLength = Math.min(mean.length, std.length);

                // Y軸比例尺
                const yMin = d3.min(mean, (d, j) => d - 3 * std[j]);
                const yMax = d3.max(mean, (d, j) => d + 3 * std[j]);

                const y = d3.scaleLinear()
                    .domain([yMin, yMax])
                    .nice()
                    .range([subplotH - 50, 10]);

                // X軸比例尺
                const x = d3.scaleLinear()
                    .domain([0, dataLength - 1])
                    .range([0, chartW]);

                // 繪製99%置信區間
                const area99 = d3.area()
                    .x((d, idx) => x(idx))
                    .y0((d, idx) => y(d - sigmaLevels['99%'] * std[idx]))
                    .y1((d, idx) => y(d + sigmaLevels['99%'] * std[idx]))
                    .curve(d3.curveLinear);

                g.append('path')
                    .datum(mean)
                    .attr('fill', 'rgba(173, 216, 230, 0.3)')
                    .attr('stroke', 'none')
                    .attr('d', area99);

                // 繪製50%置信區間
                const area50 = d3.area()
                    .x((d, idx) => x(idx))
                    .y0((d, idx) => y(d - sigmaLevels['50%'] * std[idx]))
                    .y1((d, idx) => y(d + sigmaLevels['50%'] * std[idx]))
                    .curve(d3.curveLinear);

                g.append('path')
                    .datum(mean)
                    .attr('fill', 'rgba(135, 206, 250, 0.5)')
                    .attr('stroke', 'none')
                    .attr('d', area50);

                // 繪製樣本路徑
                for (let s = 1; s <= numSamples; s++) {
                    const sampleKey = `sample${s}_${comp.key}`;
                    if (data[0][sampleKey] !== undefined) {
                        const sampleData = data.map(d => +d[sampleKey]).filter(v => !isNaN(v));
                        if (sampleData.length > 0) {
                            g.append('path')
                                .datum(sampleData.slice(0, dataLength))
                                .attr('fill', 'none')
                                .attr('stroke', sampleColors[(s - 1) % sampleColors.length])
                                .attr('stroke-width', 0.8)
                                .attr('opacity', 0.7)
                                .attr('d', d3.line()
                                    .x((d, idx) => x(idx))
                                    .y(d => y(d))
                                    .curve(d3.curveLinear)
                                );
                        }
                    }
                }

                // 繪製均值線
                g.append('path')
                    .datum(mean)
                    .attr('fill', 'none')
                    .attr('stroke', '#1a237e')
                    .attr('stroke-width', 1.5)
                    .attr('d', d3.line()
                        .x((d, idx) => x(idx))
                        .y(d => y(d))
                        .curve(d3.curveLinear)
                    );

                // 繪製底部相關性色帶（簡化版本）
                if (corr.length > 0) {
                    const corrBarY = subplotH - 45;
                    const corrBarHeight = 20;

                    for (let idx = 0; idx < Math.min(dataLength, corr.length); idx++) {
                        const cval = corr[idx];
                        if (!isNaN(cval)) {
                            // 簡單的藍紅配色
                            let color;
                            if (cval > 0) {
                                color = `rgba(255, ${255 - Math.round(cval * 255)}, ${255 - Math.round(cval * 255)}, 0.8)`; // 紅色
                            } else {
                                color = `rgba(${255 + Math.round(cval * 255)}, ${255 + Math.round(cval * 255)}, 255, 0.8)`; // 藍色
                            }

                            // 每格的高度基於不確定性
                            const uncertainty = std[idx] || 0;
                            const maxUncertainty = d3.max(std) || 1;
                            const barHeight = (uncertainty / maxUncertainty) * corrBarHeight;

                            g.append('rect')
                                .attr('x', x(idx) - chartW / dataLength / 2)
                                .attr('y', corrBarY + (corrBarHeight - barHeight) / 2)
                                .attr('width', Math.max(1, chartW / dataLength))
                                .attr('height', barHeight)
                                .attr('fill', color)
                                .attr('stroke', 'none');
                        }
                    }
                }

                // coPoint垂直線
                if (coPoint !== null && coPoint >= 0 && coPoint < dataLength) {
                    g.append('line')
                        .attr('x1', x(coPoint))
                        .attr('x2', x(coPoint))
                        .attr('y1', 10)
                        .attr('y2', subplotH - 50)
                        .attr('stroke', 'black')
                        .attr('stroke-width', 2);
                }

                // 組件標題
                g.append('text')
                    .attr('x', chartW / 2)
                    .attr('y', 0)
                    .attr('text-anchor', 'middle')
                    .attr('font-size', 14)
                    .attr('font-weight', 'bold')
                    .attr('fill', '#333')
                    .text(comp.title);

                // Y軸
                g.append('g')
                    .call(d3.axisLeft(y).ticks(4))
                    .selectAll('text')
                    .attr('fill', '#555')
                    .attr('font-size', 10);

                // 零線（對於季節性和殘差組件）
                if (i > 1) {
                    g.append('line')
                        .attr('x1', 0)
                        .attr('x2', chartW)
                        .attr('y1', y(0))
                        .attr('y2', y(0))
                        .attr('stroke', '#999')
                        .attr('stroke-width', 0.5)
                        .attr('stroke-dasharray', '2,2');
                }

                // 最後一個子圖的X軸
                if (i === componentInfo.length - 1) {
                    g.append('g')
                        .attr('transform', `translate(0, ${subplotH - 50})`)
                        .call(d3.axisBottom(x).ticks(8))
                        .selectAll('text')
                        .attr('fill', '#555')
                        .attr('font-size', 10);

                    g.append('text')
                        .attr('x', chartW / 2)
                        .attr('y', subplotH - 10)
                        .attr('text-anchor', 'middle')
                        .attr('font-size', 12)
                        .attr('fill', '#333')
                        .text('Time Index (Days since start)');
                }
            });

        }).catch(error => {
            console.error('Error loading UASTL data:', error);
        });

    }, [range]);

    return (
        <div style={{ width: '100%', height: '100%', background: 'none' }}>
            <div ref={d3Container} style={{
                width: '100%',
                height: '100%',
                borderRadius: '12px',
                overflow: 'hidden',
                position: 'relative',
                background: '#ffffff'
            }} />
        </div>
    );
}

export default UASTLChart;
